// Collect all rows
const rows = $input.all().map(i => i.json);
const uploadedAt = new Date().toISOString();

if (rows.length === 0) {
  return [{ json: { nombre_lignes: 0, resume_texte: 'The file is empty, no data found.', resume_html: '<p>The file is empty.</p>', students: [], stats: [] } }];
}

// Find numeric columns
const columns = Object.keys(rows[0]);
const numericColumns = [];

for (const col of columns) {
  let numericCount = 0;
  let total = 0;
  for (const r of rows) {
    const raw = r[col];
    if (raw === null || raw === undefined || raw === '') continue;
    const cleaned = String(raw).replace(/[^0-9.,\-]/g, '').replace(/,/g, '.');
    const num = parseFloat(cleaned);
    total++;
    if (!isNaN(num)) numericCount++;
  }
  if (total > 0 && numericCount / total >= 0.8) {
    numericColumns.push(col);
  }
}

// Compute statistics per numeric column
const stats = [];
for (const col of numericColumns) {
  const values = [];
  for (const r of rows) {
    const raw = r[col];
    if (raw === null || raw === undefined || raw === '') continue;
    const cleaned = String(raw).replace(/[^0-9.,\-]/g, '').replace(/,/g, '.');
    const num = parseFloat(cleaned);
    if (!isNaN(num)) values.push(num);
  }
  if (values.length === 0) continue;

  const sum = values.reduce((a, b) => a + b, 0);
  const count = values.length;
  const moyenne = sum / count;
  const min = Math.min(...values);
  const max = Math.max(...values);

  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  const mediane = sorted.length % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;

  const variance = values.reduce((a, b) => a + Math.pow(b - moyenne, 2), 0) / count;
  const ecartType = Math.sqrt(variance);

  stats.push({
    colonne: col,
    somme: Math.round(sum * 100) / 100,
    moyenne: Math.round(moyenne * 100) / 100,
    mediane: Math.round(mediane * 100) / 100,
    min_val: min,
    max_val: max,
    ecart_type: Math.round(ecartType * 100) / 100,
    nombre_valeurs: count,
    uploaded_at: uploadedAt,
  });
}

// ---- Build text summary (for the AI, in English) ----
let resumeTexte = 'Number of rows: ' + rows.length + '\n';
resumeTexte += 'Columns: ' + columns.join(', ') + '\n\n';
for (const s of stats) {
  resumeTexte += 'Column "' + s.colonne + '": sum=' + s.somme + ', mean=' + s.moyenne + ', median=' + s.mediane + ', min=' + s.min_val + ', max=' + s.max_val + ', std-dev=' + s.ecart_type + ', count=' + s.nombre_valeurs + '\n';
}
if (stats.length === 0) resumeTexte += 'No numeric columns found in the file.\n';

// ---- Build HTML: table 1 = students, table 2 = averages ----
let studentsHtml = '<h2>Students table</h2>';
studentsHtml += '<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-family:Arial,sans-serif;">';
studentsHtml += '<tr style="background:#f2f2f2;">';
for (const col of columns) {
  studentsHtml += '<th>' + col + '</th>';
}
studentsHtml += '</tr>';
for (const r of rows) {
  studentsHtml += '<tr>';
  for (const col of columns) {
    const v = (r[col] === null || r[col] === undefined) ? '' : r[col];
    studentsHtml += '<td>' + v + '</td>';
  }
  studentsHtml += '</tr>';
}
studentsHtml += '</table>';

let avgHtml = '<h2>Averages / Statistics table</h2>';
if (stats.length > 0) {
  avgHtml += '<table border="1" cellpadding="6" cellspacing="0" style="border-collapse:collapse;font-family:Arial,sans-serif;">';
  avgHtml += '<tr style="background:#f2f2f2;"><th>Column</th><th>Sum</th><th>Mean</th><th>Median</th><th>Min</th><th>Max</th><th>Std-dev</th><th>Count</th></tr>';
  for (const s of stats) {
    avgHtml += '<tr><td>' + s.colonne + '</td><td>' + s.somme + '</td><td>' + s.moyenne + '</td><td>' + s.mediane + '</td><td>' + s.min_val + '</td><td>' + s.max_val + '</td><td>' + s.ecart_type + '</td><td>' + s.nombre_valeurs + '</td></tr>';
  }
  avgHtml += '</table>';
} else {
  avgHtml += '<p>No numeric columns found in the file.</p>';
}

const resumeHtml = '<p><b>Number of rows:</b> ' + rows.length + '</p>' + studentsHtml + '<br>' + avgHtml;

return [{
  json: {
    nombre_lignes: rows.length,
    colonnes: columns,
    resume_texte: resumeTexte,
    resume_html: resumeHtml,
    students: rows,
    stats: stats,
  },
}];

